}
(#EmailProvider).emailprovider_sendmail("test@example.com","화재 경고","화재가 발생했습니다. 대피하세요")"}

{"name":"CaptureImageEvery10SecondsOnMotion","cron":"","period":0,"code":"active := 0
prev := (#MotionSensor).motionsensor_motion
curr = (#MotionSensor).motionsensor_motion
if (active == 0) {
    wait until (curr == true)
    active = 1
}
if (active == 1) {
    if (prev == false and curr == true) {
        (#Camera).camera_captureimage()
    }
}
prev = curr"}

{"name":"CloseAllWindowsAndDoorsWhenRains","cron":"","period":100,"code":"prev := (#RainSensor).rainsensor_rain
curr = (#RainSensor).rainsensor_rain
if (prev == false and curr == true) {
    all(#Window).windowcovering_downorclose()
    all(#Door).door_close()
}
prev = curr"}

{"name":"TurnOnEntranceLightFor3Seconds","cron":"","period":100,"code":"prev := (#Entrance #PresenceSensor).presencesensor_presence

curr = (#Entrance #PresenceSensor).presencesensor_presence

if (prev == false and curr == true) {

    (#Entrance #Light).levelcontrol_movetolevel(100, 0)

    delay(3 SEC)

    (#Entrance #Light).switch_off()

}

prev = curr"}

